//! Proof for `src/w4pm_algorithms_invocation_dispatch.rs`: asserts the
//! composable set is exactly the SPARQL-derived `pi:verifiedAgainst` rows
//! (currently 1 of 60), that the one composable row actually runs the real
//! `wasm4pm-compat::dfg::discover_ocel_dfg` and returns a correct DFG, and
//! that every OTHER catalog id fails closed with `NotComposable` rather
//! than panicking or silently succeeding.
//!
//! Generated by `wasm4pm-algorithms-pack`.

#[path = "../src/w4pm_algorithms_invocation_dispatch.rs"]
mod w4pm_algorithms_invocation_dispatch;

use w4pm_algorithms_invocation_dispatch::{
    dispatch_verified, AlgorithmId, DispatchError, CATALOG, COMPOSABLE,
};

fn minimal_ocel() -> wasm4pm_compat::ocel::OCEL {
    use chrono::DateTime;
    use wasm4pm_compat::ocel::{OCELEvent, OCELRelationship, OCELType, OCEL};

    let time_a = DateTime::parse_from_rfc3339("2026-07-18T00:00:00+00:00")
        .expect("literal RFC 3339 timestamp must parse");
    let time_b = DateTime::parse_from_rfc3339("2026-07-18T00:01:00+00:00")
        .expect("literal RFC 3339 timestamp must parse");

    OCEL {
        event_types: vec![
            OCELType { name: "receive_order".to_string(), attributes: Vec::new() },
            OCELType { name: "ship_order".to_string(), attributes: Vec::new() },
        ],
        object_types: Vec::new(),
        events: vec![
            OCELEvent {
                id: "e1".to_string(),
                event_type: "receive_order".to_string(),
                time: time_a,
                attributes: Vec::new(),
                relationships: vec![OCELRelationship {
                    object_id: "order-1".to_string(),
                    qualifier: "order".to_string(),
                }],
            },
            OCELEvent {
                id: "e2".to_string(),
                event_type: "ship_order".to_string(),
                time: time_b,
                attributes: Vec::new(),
                relationships: vec![OCELRelationship {
                    object_id: "order-1".to_string(),
                    qualifier: "order".to_string(),
                }],
            },
        ],
        objects: Vec::new(),
    }
}

#[test]
fn composable_set_is_exactly_the_sparql_derived_verified_rows() {
    // This is an honesty tripwire, not a tautology: it fails if someone
    // adds a `pi:verifiedAgainst` fact to the ontology without adding a
    // matching real dispatch arm (COMPOSABLE would then diverge from
    // `verified`), or vice versa.
    let expected: &[AlgorithmId] = &[
        AlgorithmId::OcelDfg,
    ];
    assert_eq!(COMPOSABLE, expected);
    assert_eq!(COMPOSABLE.len(), 1, "exactly 1 of 60 rows is currently real-invocation composable");
}

#[test]
fn the_one_composable_row_actually_runs_the_real_target_function() {
    let ocel = minimal_ocel();
    let dfg = dispatch_verified(AlgorithmId::OcelDfg, &ocel)
        .expect("OcelDfg must be composable — it carries pi:verifiedAgainst");
    assert_eq!(dfg.nodes.len(), 2);
    assert_eq!(dfg.edges.len(), 1);
    assert_eq!(dfg.edges[0].source, "receive_order");
    assert_eq!(dfg.edges[0].target, "ship_order");
    assert_eq!(dfg.edges[0].frequency, 1);
}

#[test]
fn every_non_composable_catalog_id_fails_closed_not_silently_or_by_panic() {
    let ocel = minimal_ocel();
    let non_composable_count = CATALOG
        .iter()
        .filter(|row| row.id != AlgorithmId::OcelDfg)
        .map(|row| {
            match dispatch_verified(row.id, &ocel) {
                Err(DispatchError::NotComposable(id)) => assert_eq!(id, row.id),
                Ok(_) => panic!(
                    "{:?} unexpectedly succeeded — it must not be in \
                     wasm4pm-compat's real API surface unless a \
                     pi:verifiedAgainst fact + matching dispatch arm exist",
                    row.id
                ),
            }
        })
        .count();
    // 59 of 60 catalog rows must fail closed.
    assert_eq!(non_composable_count, CATALOG.len() - 1);
}
